prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?betweenTask ?betweenTaskName (COUNT(DISTINCT ?flowPath) AS ?pathCount) WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2d887704e5324e6bb2126cef061e50e9" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?startTask a bboExt:ChoreographyTask ;
             tai:belongsTo ?choreo ;
             bbo:name ?startTaskName .
  FILTER(LCASE(STR(?startTaskName)) = LCASE("Receive invoice"))

  ?endTask a bboExt:ChoreographyTask ;
           tai:belongsTo ?choreo ;
           bbo:name ?endTaskName .
  FILTER(LCASE(STR(?endTaskName)) = LCASE("Check invoice completeness"))

  ?startTask ((^bbo:has_sourceRef)/bbo:has_targetRef)* ?betweenTask .
  ?betweenTask a bboExt:ChoreographyTask ;
               tai:belongsTo ?choreo .

  # ensure betweenTask is reachable from startTask without passing endTask first
  FILTER NOT EXISTS {
    ?startTask ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?mid .
    ?mid a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?midName .
    FILTER(LCASE(STR(?midName)) = LCASE("Check invoice completeness"))
    FILTER(?mid != ?betweenTask)
  }

  FILTER(?betweenTask != ?startTask)
  FILTER(?betweenTask != ?endTask)

  OPTIONAL { ?betweenTask bbo:name ?betweenTaskName . }
  OPTIONAL { BIND(1 AS ?flowPath) }
}
GROUP BY ?betweenTask ?betweenTaskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2d887704e5324e6bb2126cef061e50e9" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("Receive invoice")))
}
LIMIT 25

