prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?type ?label ?comment ?id WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2d887704e5324e6bb2126cef061e50e9" ;
         tai:belongsTo ?org .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?elem tai:belongsTo ?choreo ;
        a ?type .

  OPTIONAL { ?elem bbo:name ?label . }
  OPTIONAL { ?elem rdfs:comment ?comment . }
  OPTIONAL { ?elem bbo:id ?id . }
  FILTER(?type IN (bboExt:ChoreographyTask, bboExt:StartEvent, bboExt:EndEvent, bboExt:IntermediateCatchEvent,
                    bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
}
LIMIT 25

